INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '88b383b4-8e7f-4827-8137-a0be7d98bf74',
  '00000000-0000-0000-0000-000000000001',
  $escape$anthropic_api — Tokens, Context Windows, and Sampling Parameters Demystified$escape$,
  $escape$Claude models on the Anthropic API expose three key sampling levers. `temperature` (0–1) scales the logit distribution before softmax — 0 collapses it to greedy decoding, 1 leaves it maximally stochastic. `top_p` (nucleus sampling) trims the vocabulary to the smallest set whose cumulative probability exceeds the threshold; `top_p=0.9` means the model samples only from tokens covering 90% of the probability mass. Uniquely, Anthropic also exposes `top_k`, which hard-caps the candidate pool by count — when both are set, they apply in sequence.

Context window: claude-sonnet-4-6 and claude-opus-4-6 support 200k input tokens. Use `client.messages.count_tokens()` to audit prompts before sending — it returns the exact token count the API will charge, preventing silent context overflow. `max_tokens` is a hard output ceiling, not a target; Claude stops earlier at a natural end. Always inspect `response.usage`: it surfaces `cache_read_input_tokens` and `cache_creation_input_tokens` alongside standard counts when prompt caching is active, letting you measure real cache hit rates.$escape$,
  $escape$import anthropic

client = anthropic.Anthropic()

# Audit token cost before sending
count = client.messages.count_tokens(
    model="claude-sonnet-4-6",
    messages=[{"role": "user", "content": "Explain attention mechanisms."}]
)
print(f"Estimated input tokens: {count.input_tokens}")

response = client.messages.create(
    model="claude-sonnet-4-6",
    max_tokens=512,
    temperature=0.3,   # Low entropy for factual output
    top_p=0.9,         # Nucleus sampling threshold
    top_k=40,          # Applied after top_p filter
    messages=[{"role": "user", "content": "Explain attention mechanisms."}]
)

print(response.content[0].text)
print(response.usage)  # includes cache_read_input_tokens if caching is active$escape$,
  $escape$python$escape$,
