INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fcf766e0-147d-4e19-a649-f1e4520cb094',
  '00000000-0000-0000-0000-000000000001',
  $escape$Anthropic API RAG — Chunking, Voyage Embeddings, and Claude as Your Reranker$escape$,
  $escape$Anthropic doesn't ship its own embedding model — pair Claude with Voyage AI (`voyage-3` or `voyage-code-3` for code corpora) for embeddings. Chunk at 512 tokens with ~10% overlap; Voyage's 32k input window handles aggressive context merging at retrieval time.

Claude's 200k-token context is RAG's biggest architectural lever: retrieve 20–40 chunks instead of 3–5, then let Claude synthesize across them rather than hallucinate from sparse context. For cross-encoder reranking without deploying a dedicated model, prompt Claude to score each `(query, chunk)` pair and return structured JSON. It outperforms bi-encoder rerankers on domain-specific corpora because it reads query and chunk jointly.

The real Anthropic-specific unlock: prompt caching. Pass your top-k reranked chunks as the system prompt with `cache_control: {"type": "ephemeral"}`. On repeated queries against the same document set, cached input tokens cost 10× less and return ~80% faster — critical for high-QPS retrieval pipelines. Combine with `tool_choice: {"type": "tool", "name": "retrieve"}` to force grounded generation and eliminate fabricated citations.$escape$,
  $escape$import anthropic, json

client = anthropic.Anthropic()

def rag_with_claude(query: str, chunks: list[str]) -> str:
    scoring = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=256,
        messages=[{"role": "user", "content":
            f"Score relevance 0-10 per chunk. Return JSON: [{{\"i\":int,\"s\":int}}]\nQuery: {query}\nChunks: {json.dumps(list(enumerate(chunks)))}"
        }]
    )
    ranked = sorted(json.loads(scoring.content[0].text), key=lambda x: x["s"], reverse=True)
    top = [chunks[r["i"]] for r in ranked[:5]]

    return client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=1024,
        system=[{"type": "text", "text": "\n\n".join(top), "cache_control": {"type": "ephemeral"}}],
        messages=[{"role": "user", "content": query}]
    ).content[0].text$escape$,
  $escape$python$escape$,
