INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bb21f1ff-1681-4e3b-aa21-4e774c3ddc0f',
  '00000000-0000-0000-0000-000000000001',
  $escape$anthropic_api Tool Use — Forcing Structured JSON Without a Dedicated Mode$escape$,
  $escape$Unlike OpenAI's `response_format: { type: 'json_object' }`, the Anthropic API has no standalone JSON mode. The idiomatic pattern for structured outputs is tool use: define a tool with a strict `input_schema`, then set `tool_choice={"type": "tool", "name": "your_tool"}` to force the model to call it. Claude's response will have `stop_reason="tool_use"` and a content block of type `tool_use` whose `input` field is already a parsed dict — no `JSON.parse` required. This is more reliable than prompt-engineering JSON because the model is constrained by schema at the sampling level. For chat completions, `client.messages.create()` is the sole entry point — there's no `/v1/chat/completions` path. Anthropic has no embeddings endpoint; use Voyage AI (`voyage-3`) via the Anthropic-partnered SDK or directly. For multi-turn, manually append the assistant's `tool_use` block and a `tool_result` user block back into `messages` — the API is stateless and context is your responsibility.$escape$,
  $escape$import anthropic

client = anthropic.Anthropic()

response = client.messages.create(
    model="claude-sonnet-4-5",
    max_tokens=256,
    tools=[{
        "name": "extract_metadata",
        "description": "Extract structured metadata from text.",
        "input_schema": {
            "type": "object",
            "properties": {
                "title": {"type": "string"},
                "tags": {"type": "array", "items": {"type": "string"}},
                "difficulty": {"type": "string", "enum": ["beginner", "intermediate", "advanced"]}
            },
            "required": ["title", "tags", "difficulty"]
        }
    }],
    tool_choice={"type": "tool", "name": "extract_metadata"},
    messages=[{"role": "user", "content": "Rust async/await with Tokio for building HTTP servers."}]
)

result = next(b for b in response.content if b.type == "tool_use")
print(result.input)  # Already a dict — no JSON parsing needed$escape$,
  $escape$python$escape$,
