INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3e43ab00-1045-4ad1-aff2-34ecc9740d16',
  '00000000-0000-0000-0000-000000000001',
  $escape$anthropic_api + Ollama — Local-First Dev Without Burning API Credits$escape$,
  $escape$When building with the Anthropic Python SDK, every prompt costs tokens—including throwaway test calls during development. Ollama runs open-weight models (Llama 3.2, Mistral, Gemma 2) locally, and LiteLLM exposes them behind an Anthropic-compatible REST interface. Point `anthropic.Anthropic(base_url=...)` at `localhost:4000` and your existing `client.messages.create()` calls work unchanged—no API key, no latency, no data leaving your machine.

The swap is one env var: `ANTHROPIC_BASE_URL`. In dev, point it at LiteLLM proxying `ollama/llama3.2`. In prod, unset it and the SDK falls back to `api.anthropic.com`. Your `MessageParam` schemas, tool definitions, and system prompt logic stay identical—only the inference backend changes.

Privacy benefit is concrete: customer PII or proprietary code never reaches Anthropic's servers during iteration. Once prompts are stable, flip to `claude-sonnet-4-5` for production-quality output. The pattern also pays off in CI—spin up Ollama in a Docker service step, run your integration tests against real `messages.create()` calls, consume zero quota.$escape$,
  $escape$import anthropic
import os

client = anthropic.Anthropic(
    api_key=os.getenv("ANTHROPIC_API_KEY", "sk-local"),
    base_url=os.getenv("ANTHROPIC_BASE_URL", "https://api.anthropic.com"),
)

response = client.messages.create(
    model=os.getenv("MODEL_ID", "claude-sonnet-4-5"),
    max_tokens=512,
    messages=[{"role": "user", "content": "Summarize this diff: ..."}],
)
print(response.content[0].text)
# Dev:  ANTHROPIC_BASE_URL=http://localhost:4000 MODEL_ID=ollama/llama3.2 python main.py
# Prod: unset ANTHROPIC_BASE_URL, use real ANTHROPIC_API_KEY$escape$,
  $escape$python$escape$,
