INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ee2f60a4-a4ef-4019-b0de-13e7bb6d6abd',
  '00000000-0000-0000-0000-000000000001',
  $escape$anthropic_api — LLM-as-Judge, RAGAS, and Batch Benchmarking$escape$,
  $escape$Claude's Messages API makes a reliable LLM-as-judge backbone. The key is a structured system prompt that enforces JSON scoring — claude-sonnet-4-6 follows strict output schemas consistently. Always set temperature=0 for deterministic, reproducible scores across eval runs.

For RAG pipelines, RAGAS integrates via its LangchainLLMWrapper using langchain-anthropic, giving you faithfulness, answer relevancy, and context precision metrics powered by the same Claude model driving your RAG stack — removing cross-model scoring bias.

For custom evals, parse scores directly from response.content[0].text. When benchmarking haiku vs sonnet, track response.usage.input_tokens and wall-clock latency per prompt to build cost/quality Pareto curves — critical for choosing the right model tier per eval category.

For large benchmark suites (MMLU-style, 1,000+ prompts), use client.messages.batches.create() — the Batch API handles up to 10,000 requests asynchronously at 50% cost reduction. Pass a custom_id per eval item so you can join results back to ground-truth labels without index juggling.$escape$,
  $escape$import anthropic, json

client = anthropic.Anthropic()

def llm_judge(question: str, context: str, answer: str) -> dict:
    msg = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=256,
        temperature=0,
        system='Score this RAG answer. Return ONLY JSON: {"faithfulness": 0.0-1.0, "relevance": 0.0-1.0, "reason": "string"}',
        messages=[{"role": "user", "content": f"Q: {question}\nCtx: {context}\nA: {answer}"}],
    )
    return json.loads(msg.content[0].text)$escape$,
  $escape$python$escape$,
